### C++ Program: Dictionary Using Binary Search Tree

Below is a well-structured C++ program that implements a dictionary using a Binary Search Tree (BST) to store words and their definitions. The program allows users to:
- Insert words and definitions.
- Lookup a word and retrieve its definition.
- Delete a word and its definition.
- Display the entire dictionary.

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

using namespace std;

// Node structure for BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST operations
class Dictionary {
private:
    Node* root;

    // Helper function to insert a node
    void insert(Node* &root, string word, string definition);

    // Helper function to search for a word
    Node* search(Node* root, string word);

    // Helper function to delete a node
    void deleteNode(Node* &root, string word);

    // Helper function to print the tree
    void printTree(Node* node, string indent, bool isLeft);

public:
    Dictionary() : root(nullptr) {}

    void insert(string word, string definition) {
        insert(root, word, definition);
    }

    Node* search(string word) {
        return search(root, word);
    }

    void deleteWord(string word) {
        deleteNode(root, word);
    }

    void displayDictionary() {
        cout << "Dictionary:" << endl;
        printTree(root, "", true);
    }

    // Helper function to print the tree
    void printTree(Node* node, string indent, bool isLeft) {
        if (node == nullptr) return;

        // Print the current node
        cout << indent << node->word << " : " << node->definition << endl;

        // Recursively print the left subtree
        printTree(node->left, indent + "   ", true);

        // Recursively print the right subtree
        printTree(node->right, indent + "   ", false);
    }
};

// Insert function
void Dictionary::insert(Node* &root, string word, string definition) {
    if (root == nullptr) {
        root = new Node(word, definition);
        return;
    }

    if (word < root->word) {
        insert(root->left, word, definition);
    } else if (word > root->word) {
        insert(root->right, word, definition);
    }
}

// Search function
Node* Dictionary::search(Node* root, string word) {
    if (root == nullptr) return nullptr;

    if (word == root->word) return root;

    if (word < root->word) {
        return search(root->left, word);
    } else {
        return search(root->right, word);
    }
}

// Delete function
void Dictionary::deleteNode(Node* &root, string word) {
    if (root == nullptr) return;

    if (word < root->word) {
        deleteNode(root->left, word);
    } else if (word > root->word) {
        deleteNode(root->right, word);
    } else {
        // Found the word
        if (root->left == nullptr) {
            Node* temp = root->right;
            delete root;
            root = temp;
        } else if (root->right == nullptr) {
            Node* temp = root->left;
            delete root;
            root = temp;
        } else {
            // Find the in-order successor
            Node* temp = root->right;
            while (temp->left != nullptr) {
                temp = temp->left;
            }

            // Copy the in-order successor's value
            root->word = temp->word;
            root->definition = temp->definition;

            // Delete the in-order successor
            deleteNode(root->right, temp->word);
        }
    }
}

int main() {
    Dictionary dict;

    string word, definition;
    cout << "Enter words and definitions (type 'exit' to stop):" << endl;

    while (true) {
        cout << "> ";
        getline(cin, word);
        if (word == "exit") break;

        cout << "Enter definition: ";
        getline(cin, definition);
        dict.insert(word, definition);
    }

    dict.displayDictionary();

    cout << "\nDictionary operations:" << endl;
    cout << "1. Lookup a word" << endl;
    cout << "2. Delete a word" << endl;
    cout << "3. Exit" << endl;

    int choice;
    while (true) {
        cout << "Enter your choice: ";
        cin >> choice;
        cin.ignore();

        switch (choice) {
            case 1:
                cout << "Enter a word to look up: ";
                string searchWord;
                getline(cin, searchWord);
                Node* result = dict.search(searchWord);
                if (result) {
                    cout << "Definition: " << result->definition << endl;
                } else {
                    cout << "Word not found." << endl;
                }
                break;
            case 2:
                cout << "Enter a word to delete: ";
                string deleteWord;
                getline(cin, deleteWord);
                dict.deleteWord(deleteWord);
                cout << "Word deleted." << endl;
                break;
            case 3:
                return 0;
            default:
                cout << "Invalid choice. Try again." << endl;
        }
    }

    return 0;
}
```

