Below is a C++ program that implements a dictionary using a Binary Search Tree (BST). It allows users to insert words and their definitions, search for words, delete words, and print the entire dictionary.

```cpp
#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

using namespace std;

// Node structure for the BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST operations
class DictionaryBST {
private:
    Node* root;

    // Helper function to insert a node
    Node* insert(Node* node, string word, string definition);

    // Helper function to search for a word
    Node* search(Node* node, string word);

    // Helper function to delete a node
    Node* deleteNode(Node* node, string word);

    // Helper function to print the tree in-order
    void inOrderTraversal(Node* node, vector<string>& results);

public:
    DictionaryBST() : root(nullptr) {}

    // Insert a word-definition pair into the BST
    void insert(string word, string definition) {
        root = insert(root, word, definition);
    }

    // Search for a word in the BST
    Node* search(string word) {
        return search(root, word);
    }

    // Delete a word from the BST
    void deleteWord(string word) {
        root = deleteNode(root, word);
    }

    // Print all words and definitions in the dictionary
    void printDictionary() {
        vector<string> results;
        inOrderTraversal(root, results);
        for (const auto& result : results) {
            cout << result << endl;
        }
    }

    // Helper functions
    Node* insert(Node* node, string word, string definition) {
        if (node == nullptr) {
            return new Node(word, definition);
        }

        if (word < node->word) {
            node->left = insert(node->left, word, definition);
        } else if (word > node->word) {
            node->right = insert(node->right, word, definition);
        }

        return node;
    }

    Node* search(Node* node, string word) {
        if (node == nullptr) {
            return nullptr;
        }

        if (word == node->word) {
            return node;
        }

        if (word < node->word) {
            return search(node->left, word);
        } else {
            return search(node->right, word);
        }
    }

    Node* deleteNode(Node* node, string word) {
        if (node == nullptr) {
            return node;
        }

        if (word < node->word) {
            node->left = deleteNode(node->left, word);
        } else if (word > node->word) {
            node->right = deleteNode(node->right, word);
        } else {
            // Node found; delete it
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                node = temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                node = temp;
            } else {
                // Node has two children; find the inorder successor
                Node* temp = node->right;
                while (temp->left != nullptr) {
                    temp = temp->left;
                }

                // Copy the inorder successor's value to current node
                node->word = temp->word;
                node->definition = temp->definition;

                // Delete the inorder successor
                node->right = deleteNode(node->right, temp->word);
            }
        }

        return node;
    }

    void inOrderTraversal(Node* node, vector<string>& results) {
        if (node != nullptr) {
            inOrderTraversal(node->left, results);
            results.push_back(node->word);
            results.push_back(node->definition);
            inOrderTraversal(node->right, results);
        }
    }
};

int main() {
    DictionaryBST dict;

    string word, definition;
    cout << "Enter words and their definitions (type 'exit' to quit):\n";

    while (true) {
        cout << "> ";
        cin >> word;
        if (word == "exit") {
            break;
        }
        cout << "Enter definition: ";
        cin >> definition;
        dict.insert(word, definition);
    }

    cout << "\nDictionary Contents:\n";
    dict.printDictionary();

    cout << "\nOperations:\n";
    cout << "1. Search for a word\n";
    cout << "2. Delete a word\n";
    cout << "3. Exit\n";

    int choice;
    while (true) {
        cout << "\nChoose an operation: ";
        cin >> choice;
